struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline float half_to_float_scalar(uint16_t h) {
  uint32_t sign = (static_cast<uint32_t>(h & 0x8000u)) << 16;
  uint32_t exp = (h & 0x7C00u) >> 10;
  uint32_t mant = h & 0x03FFu;
  uint32_t fbits = 0;

  if (exp == 0x1Fu) {
    fbits = sign | 0x7F800000u | (mant << 13);
  } else if (exp != 0) {
    fbits = sign | ((exp + 112u) << 23) | (mant << 13);
  } else if (mant != 0) {
    exp = 113u;
    while ((mant & 0x0400u) == 0) {
      mant <<= 1;
      --exp;
    }
    mant &= 0x03FFu;
    fbits = sign | (exp << 23) | (mant << 13);
  } else {
    fbits = sign;
  }

  float out;
  std::memcpy(&out, &fbits, sizeof(out));
  return out;
}

static inline uint16_t float_to_half_scalar(float f) {
  uint32_t bits;
  std::memcpy(&bits, &f, sizeof(bits));

  uint32_t sign = (bits >> 16) & 0x8000u;
  uint32_t exp = (bits >> 23) & 0xFFu;
  uint32_t mant = bits & 0x7FFFFFu;

  if (exp == 0xFFu) {
    if (mant != 0) {
      uint16_t nan_mant = static_cast<uint16_t>(mant >> 13);
      if (nan_mant == 0) nan_mant = 1;
      return static_cast<uint16_t>(sign | 0x7C00u | nan_mant);
    }
    return static_cast<uint16_t>(sign | 0x7C00u);
  }

  int32_t half_exp = static_cast<int32_t>(exp) - 127 + 15;

  if (half_exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7C00u);
  }

  if (half_exp <= 0) {
    if (half_exp < -10) {
      return static_cast<uint16_t>(sign);
    }
    mant |= 0x800000u;
    uint32_t shifted = mant >> (1 - half_exp);
    return static_cast<uint16_t>(sign | ((shifted + 0x1000u) >> 13));
  }

  uint32_t rounded_mant = mant + 0x1000u;
  if (rounded_mant & 0x00800000u) {
    rounded_mant = 0;
    ++half_exp;
    if (half_exp >= 31) {
      return static_cast<uint16_t>(sign | 0x7C00u);
    }
  }

  return static_cast<uint16_t>(sign | (static_cast<uint32_t>(half_exp) << 10) |
                               (rounded_mant >> 13));
}

