template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  float ax = half_to_float_scalar(a.x);
  float ay = half_to_float_scalar(a.y);
  float bx = half_to_float_scalar(b.x);
  float by = half_to_float_scalar(b.y);
  float cx = half_to_float_scalar(c.x);
  float cy = half_to_float_scalar(c.y);
  return half2{float_to_half_scalar(ax * bx + cx),
