template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
static void benchmark_func(T seed, T* g_data, long total_blocks) {
  (void)TemperateUnroll;
  if (total_blocks <= 0) return;

  const unsigned int blockSize = blockdim;
  const long big_stride =
      static_cast<long>(total_blocks) * blockSize * granularity;
  const long total_threads = static_cast<long>(total_blocks) * blockSize;

#pragma omp parallel for schedule(static)
  for (long tid = 0; tid < total_threads; ++tid) {
    const long blockIdx = tid / blockSize;
    const long threadIdx = tid % blockSize;
    const long idx = blockIdx * blockSize * granularity + threadIdx;

    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; ++k) {
      for (unsigned int j = 0; j < granularity; ++j) {
        tmps[j] = g_data[idx + static_cast<long>(j) * blockSize +
                         static_cast<long>(k) * big_stride];
        for (unsigned int i = 0; i < compute_iterations; ++i) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
    }
  }
}

template <class F>
static float measure_ms(F&& fn) {
  auto start = std::chrono::high_resolution_clock::now();
  fn();
  auto stop = std::chrono::high_resolution_clock::now();
  std::chrono::duration<double, std::milli> elapsed = stop - start;
  return static_cast<float>(elapsed.count());
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
