static inline float half_bits_to_float(uint16_t h) {
  const uint32_t sign = static_cast<uint32_t>(h & 0x8000u) << 16;
  uint32_t exp = (h >> 10) & 0x1fu;
  uint32_t mant = h & 0x03ffu;
  uint32_t out;

  if (exp == 0) {
    if (mant == 0) {
      out = sign;
    } else {
      exp = 1;
      while ((mant & 0x0400u) == 0) {
        mant <<= 1;
        --exp;
      }
      mant &= 0x03ffu;
      exp = exp + (127 - 15);
      out = sign | (exp << 23) | (mant << 13);
    }
  } else if (exp == 0x1f) {
    out = sign | 0x7f800000u | (mant << 13);
  } else {
    exp = exp + (127 - 15);
    out = sign | (exp << 23) | (mant << 13);
  }

  float f;
  std::memcpy(&f, &out, sizeof(f));
  return f;
}

static inline uint16_t float_to_half_bits(float f) {
  uint32_t x;
  std::memcpy(&x, &f, sizeof(x));

  const uint16_t sign = static_cast<uint16_t>((x >> 16) & 0x8000u);
  uint32_t mant = x & 0x007fffffu;
  int exp = static_cast<int>((x >> 23) & 0xffu);

  if (exp == 255) {
    if (mant != 0) return static_cast<uint16_t>(sign | 0x7e00u);
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  exp = exp - 127 + 15;

  if (exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  if (exp <= 0) {
    if (exp < -10) return sign;
    mant |= 0x00800000u;
    const uint32_t shifted = mant >> (1 - exp);
    const uint32_t rounded = shifted + 0x00001000u;
    return static_cast<uint16_t>(sign | (rounded >> 13));
  }

  mant += 0x00001000u;
  if (mant & 0x00800000u) {
    mant = 0;
    ++exp;
    if (exp >= 31) {
      return static_cast<uint16_t>(sign | 0x7c00u);
    }
  }

  return static_cast<uint16_t>(sign | (static_cast<uint16_t>(exp) << 10) |
                               static_cast<uint16_t>(mant >> 13));
}

